import{_ as a,o as t,c as o,ag as i}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"About Memoh","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1773501089000}'),n={name:"about.md"};function r(s,e,l,c,d,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="about-memoh" tabindex="-1">About Memoh <a class="header-anchor" href="#about-memoh" aria-label="Permalink to &quot;About Memoh&quot;">​</a></h1><h2 id="what-is-memoh" tabindex="-1">What is Memoh? <a class="header-anchor" href="#what-is-memoh" aria-label="Permalink to &quot;What is Memoh?&quot;">​</a></h2><p>Memoh is a multi-member, structured long-memory, containerized AI agent system platform. You can create your own AI bots and chat with them via Telegram, Discord, Lark (Feishu), Email, Web, or CLI. Every bot has an independent container and memory system, allowing it to edit files, execute commands, and access the network within its own container — like having its own computer and brain.</p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><h3 id="multi-bot-management" tabindex="-1">Multi-Bot Management <a class="header-anchor" href="#multi-bot-management" aria-label="Permalink to &quot;Multi-Bot Management&quot;">​</a></h3><p>Create multiple bots. Humans and bots, or bots with each other, can chat privately, in groups, or collaborate. Supports role-based access control (owner / admin / member) with ownership transfer. Build bot teams, or set up accounts for family members to manage daily tasks with bots.</p><h3 id="multi-user-identity-recognition" tabindex="-1">Multi-User &amp; Identity Recognition <a class="header-anchor" href="#multi-user-identity-recognition" aria-label="Permalink to &quot;Multi-User &amp; Identity Recognition&quot;">​</a></h3><p>Bots can distinguish individual users in group chats, remember each person&#39;s context separately, and send direct messages to specific users. Cross-platform identity binding unifies the same person across Telegram, Discord, Lark, and Web.</p><h3 id="containerized-isolation" tabindex="-1">Containerized Isolation <a class="header-anchor" href="#containerized-isolation" aria-label="Permalink to &quot;Containerized Isolation&quot;">​</a></h3><p>Each bot runs in its own isolated container (powered by Containerd) with a separate filesystem and network. Bots can freely read/write files and execute commands within their containers without interfering with each other. Supports container snapshots for save/restore.</p><h3 id="memory-engineering" tabindex="-1">Memory Engineering <a class="header-anchor" href="#memory-engineering" aria-label="Permalink to &quot;Memory Engineering&quot;">​</a></h3><p>A deeply engineered, multi-provider memory layer:</p><ul><li><strong>Multi-provider architecture</strong>: Built-in (with off/sparse/dense modes), Mem0 (SaaS), and OpenViking (self-hosted or SaaS)</li><li>Automatically extracts key facts from each conversation turn and stores them as structured memories</li><li>Hybrid retrieval: semantic search (via Qdrant vector database) + keyword retrieval (BM25) + neural sparse vectors</li><li>Loads the last 24 hours of conversation context by default</li><li>Automatic memory compaction and rebuild capabilities</li><li>Multi-language auto-detection</li></ul><h3 id="multi-platform-support" tabindex="-1">Multi-Platform Support <a class="header-anchor" href="#multi-platform-support" aria-label="Permalink to &quot;Multi-Platform Support&quot;">​</a></h3><p>Unified channel adapter architecture for connecting to multiple messaging platforms:</p><ul><li><strong>Telegram</strong> — Full support with streaming, Markdown, attachments, and replies</li><li><strong>Discord</strong> — Full support</li><li><strong>Lark (Feishu)</strong> — Full support</li><li><strong>Email</strong> — Inbound webhook + outbound providers (Mailgun, generic SMTP)</li><li><strong>Web</strong> — Built-in web chat interface with streaming</li><li><strong>CLI</strong> — Command-line chat</li></ul><h3 id="agent-capabilities" tabindex="-1">Agent Capabilities <a class="header-anchor" href="#agent-capabilities" aria-label="Permalink to &quot;Agent Capabilities&quot;">​</a></h3><p>Bots come with a rich set of built-in tools:</p><ul><li><strong>Web Search</strong> — Configurable search providers (Brave, Bing, Google, Tavily, SearXNG, DuckDuckGo, and more) for real-time information</li><li><strong>Browser Automation</strong> — Use Playwright-powered browser tools for navigation, clicking, form filling, screenshots, PDF export, and rendered page inspection</li><li><strong>Subagents</strong> — Create specialized subagents with independent context, assign skills, and delegate complex tasks</li><li><strong>Skills</strong> — Define bot personality via IDENTITY.md, SOUL.md, and modular skill files that bots can enable/disable at runtime</li><li><strong>Container Operations</strong> — Read/write files, edit code, and execute commands inside the container</li><li><strong>Memory Management</strong> — Search and manage memories</li><li><strong>Text-to-Speech</strong> — Synthesize speech via configurable TTS providers (Edge TTS with 256+ voices)</li><li><strong>Messaging</strong> — Send messages and reactions to specific users or channels</li></ul><h3 id="multi-llm-provider-support" tabindex="-1">Multi-LLM Provider Support <a class="header-anchor" href="#multi-llm-provider-support" aria-label="Permalink to &quot;Multi-LLM Provider Support&quot;">​</a></h3><p>Flexibly switch between a wide range of LLM providers via four client types:</p><ul><li>OpenAI Responses API, OpenAI Chat Completions API (including compatible services)</li><li>Anthropic Messages API, Google Generative AI API</li></ul><p>Per-bot model assignment for chat, memory, and embedding.</p><h3 id="mcp-protocol-support" tabindex="-1">MCP Protocol Support <a class="header-anchor" href="#mcp-protocol-support" aria-label="Permalink to &quot;MCP Protocol Support&quot;">​</a></h3><p>Full MCP (Model Context Protocol) support via HTTP, SSE, and Stdio to connect external tool services. Built-in tools for container operations, memory search, web search, scheduling, messaging, and more. Each bot can have its own independent MCP connections.</p><h3 id="scheduled-tasks" tabindex="-1">Scheduled Tasks <a class="header-anchor" href="#scheduled-tasks" aria-label="Permalink to &quot;Scheduled Tasks&quot;">​</a></h3><p>Configure scheduled tasks using cron expressions to automatically run commands at specified times. Supports max execution count limits and manual triggers.</p><h3 id="inbox" tabindex="-1">Inbox <a class="header-anchor" href="#inbox" aria-label="Permalink to &quot;Inbox&quot;">​</a></h3><p>Cross-channel inbox — messages from other channels are queued and surfaced in the system prompt so the bot never misses context.</p><h3 id="graphical-configuration" tabindex="-1">Graphical Configuration <a class="header-anchor" href="#graphical-configuration" aria-label="Permalink to &quot;Graphical Configuration&quot;">​</a></h3><p>Modern web UI (Vue 3 + Tailwind CSS) with real-time streaming chat, tool call visualization, container filesystem browser, and visual configuration for bots, channels, providers, models, MCP, skills, and all other settings. Dark/light theme, i18n. No coding required to set up your own AI bot.</p><h3 id="cli-tool" tabindex="-1">CLI Tool <a class="header-anchor" href="#cli-tool" aria-label="Permalink to &quot;CLI Tool&quot;">​</a></h3><p>A command-line tool for bot management, channel configuration, model management, streaming chat, and more — designed for developers who prefer the terminal. See <a href="/cli/">CLI documentation</a>.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>To get Memoh running:</p><ul><li><strong><a href="/installation/docker.html">Docker</a></strong> — Recommended. One-click or manual setup with Docker Compose. Includes all services (PostgreSQL, Qdrant, Containerd, server, agent, web) — no extra dependencies on the host.</li></ul>',36)])])}const p=a(n,[["render",r]]);export{m as __pageData,p as default};
